                CourseID = 1002,
                Title = "Physics",
                Credits = 4,
                DepartmentID = 2,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Courses.AddRange(course1, course2);

            var student1 = new Student
