using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithData();
            _controller = new StudentsController(_context);
            _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStore()));
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult_WithStudents()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_SortsByNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Doe", model.First().LastName);
        }

        [Fact]
        public void Index_SortsByDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Adams", model.First().LastName);
        }

        [Fact]
        public void Index_SortsByDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Brown", model.First().LastName);
        }

        [Fact]
        public void Index_FiltersStudentsBySearchString()
        {
            var result = _controller.Index(null, null, "Doe", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Doe", model.First().LastName);
        }

        [Fact]
        public void Index_SearchByFirstName()
        {
            var result = _controller.Index(null, null, "Alice", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alice", model.First().FirstMidName);
        }

        [Fact]
        public void Index_UsesCurrentFilterWhenSearchStringIsNull()
        {
            var result = _controller.Index(null, "Doe", null, 1) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_ResetsPageToOneWhenSearchStringProvided()
        {
            var result = _controller.Index(null, null, "Doe", 5) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Details_ReturnsStudent_WhenIdIsValid()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Doe", student.LastName);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
