using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.CreateWithData();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns(System.IO.Path.GetTempPath());
            _mockEnv.Setup(e => e.ContentRootPath).Returns(System.IO.Path.GetTempPath());
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewWithAllCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ReturnsView_WhenCourseExists()
        {
            var result = _controller.Details(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Create_GET_ReturnsViewWithDepartmentList()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_POST_AddsCourseAndRedirects_WhenValid()
        {
            var course = new Course
            {
                CourseID = 2001,
                Title = "Biology",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(3, _context.Courses.Count());
        }

        [Fact]
        public void Create_POST_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 2001, DepartmentID = 1 };

            var result = _controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_POST_RejectsInvalidFileExtension()
        {
            var course = new Course
            {
                CourseID = 2001,
                Title = "Biology",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.exe", 1024);

            var result = _controller.Create(course, mockFile) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_POST_RejectsFileTooLarge()
        {
            var course = new Course
            {
                CourseID = 2001,
                Title = "Biology",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.jpg", 6 * 1024 * 1024);

            var result = _controller.Create(course, mockFile) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Edit_GET_ReturnsView_WhenCourseExists()
        {
            var result = _controller.Edit(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Edit_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_GET_ReturnsNotFound_WhenCourseDoesNotExist()
        {
            var result = _controller.Edit(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_POST_UpdatesCourseAndRedirects()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Advanced Chemistry",
                Credits = 4,
                DepartmentID = 1
            };
            var existing = _context.Courses.Find(1001);
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_POST_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1001, DepartmentID = 1 };

            var result = _controller.Edit(course, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Delete_GET_ReturnsView_WhenCourseExists()
        {
            var result = _controller.Delete(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Delete_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1001) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(_context.Courses);
        }

        private static IFormFile CreateMockFormFile(string fileName, long length)
        {
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.Length).Returns(length);
            return mock.Object;
        }
    }
}

