using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithData();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewWithInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var result = _controller.Index(1, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Index_WithCourseId_PopulatesEnrollments()
        {
            var result = _controller.Index(1, 1001) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Details_ReturnsView_WhenInstructorExists()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Smith", instructor.LastName);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenInstructorDoesNotExist()
        {
            var result = _controller.Details(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_GET_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
        }

        [Fact]
        public void Create_POST_AddsInstructorAndRedirects()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(3, _context.Instructors.Count());
        }

        [Fact]
        public void Create_POST_WithSelectedCourses_AssignsCourses()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, new[] { "1001", "1002" }) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_GET_ReturnsView_WhenInstructorExists()
        {
            var result = _controller.Edit((int?)1) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_GET_ReturnsView_WhenInstructorExists()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Smith", instructor.LastName);
        }

        [Fact]
        public void Delete_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_GET_ReturnsNotFound_WhenInstructorDoesNotExist()
        {
            var result = _controller.Delete(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(_context.Instructors);
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            // Assign instructor 1 as department administrator
            var dept = _context.Departments.Find(1);
            dept.InstructorID = 1;
            _context.SaveChanges();

            _controller.DeleteConfirmed(1);

            var updatedDept = _context.Departments.Find(1);
            Assert.Null(updatedDept.InstructorID);
        }
    }
}

