using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestDbContextFactory.CreateWithData();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void CanQueryStudents()
        {
            var students = _context.Students.ToList();
            Assert.Equal(3, students.Count);
        }

        [Fact]
        public void CanQueryCourses()
        {
            var courses = _context.Courses.ToList();
            Assert.Equal(2, courses.Count);
        }

        [Fact]
        public void CanQueryDepartments()
        {
            var departments = _context.Departments.ToList();
            Assert.Equal(2, departments.Count);
        }

        [Fact]
        public void CanQueryInstructors()
        {
            var instructors = _context.Instructors.ToList();
            Assert.Equal(2, instructors.Count);
        }

        [Fact]
        public void CanQueryEnrollments()
        {
            var enrollments = _context.Enrollments.ToList();
            Assert.Equal(3, enrollments.Count);
        }

        [Fact]
        public void CanQueryCourseAssignments()
        {
            var assignments = _context.CourseAssignments.ToList();
            Assert.Single(assignments);
        }

        [Fact]
        public void Student_IncludesEnrollments()
        {
            var student = _context.Students
                .Include(s => s.Enrollments)
                .First(s => s.ID == 1);

            Assert.Equal(2, student.Enrollments.Count);
        }

        [Fact]
        public void Course_IncludesDepartment()
        {
            var course = _context.Courses
                .Include(c => c.Department)
                .First(c => c.CourseID == 1001);

            Assert.NotNull(course.Department);
            Assert.Equal("Engineering", course.Department.Name);
        }

        [Fact]
        public void Instructor_IncludesCourseAssignments()
        {
            var instructor = _context.Instructors
                .Include(i => i.CourseAssignments)
                .First(i => i.ID == 1);

            Assert.Single(instructor.CourseAssignments);
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2024, 1, 1)
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First(s => s.LastName == "NewStudent");
            Assert.Equal("Test", retrieved.FirstMidName);
        }

        [Fact]
        public void CanDeleteStudent()
        {
            var student = _context.Students.Find(1);
            _context.Students.Remove(student);
            _context.SaveChanges();

            Assert.Equal(2, _context.Students.Count());
        }

        [Fact]
        public void CanUpdateStudent()
        {
            var student = _context.Students.Find(1);
            student.LastName = "Modified";
            _context.SaveChanges();

            var updated = _context.Students.Find(1);
            Assert.Equal("Modified", updated.LastName);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            var assignment = _context.CourseAssignments
                .First(ca => ca.CourseID == 1001 && ca.InstructorID == 1);

            Assert.NotNull(assignment);
        }
    }
}

