using ContosoUniversity.Models;
using System;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class ModelTests
    {
        [Fact]
        public void Person_FullName_ReturnsCombined()
        {
            var student = new Student { LastName = "Doe", FirstMidName = "John" };

            Assert.Equal("Doe, John", student.FullName);
        }

        [Fact]
        public void Instructor_FullName_ReturnsCombined()
        {
            var instructor = new Instructor { LastName = "Smith", FirstMidName = "Jane" };

            Assert.Equal("Smith, Jane", instructor.FullName);
        }

        [Fact]
        public void Notification_Properties_SetCorrectly()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "Test message",
                CreatedAt = now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("Test message", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 101,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/test.jpg"
            };

            Assert.Equal(101, course.CourseID);
            Assert.Equal("Test Course", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/images/test.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Department_Properties_SetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Science",
                Budget = 50000m,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = 5
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Science", dept.Name);
            Assert.Equal(50000m, dept.Budget);
            Assert.Equal(5, dept.InstructorID);
        }

        [Fact]
        public void Enrollment_Properties_SetCorrectly()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 101,
                StudentID = 42,
                Grade = Grade.A
            };

            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(101, enrollment.CourseID);
            Assert.Equal(42, enrollment.StudentID);
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment { EnrollmentID = 1, Grade = null };

            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            var assignment = new CourseAssignment
            {
                CourseID = 101,
                InstructorID = 1
            };

            Assert.Equal(101, assignment.CourseID);
            Assert.Equal(1, assignment.InstructorID);
        }

        [Fact]
        public void OfficeAssignment_Properties_SetCorrectly()
        {
            var office = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Room 101"
            };

            Assert.Equal(1, office.InstructorID);
            Assert.Equal("Room 101", office.Location);
        }

        [Fact]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        [Fact]
        public void Grade_HasExpectedValues()
        {
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(1, (int)Grade.B);
            Assert.Equal(2, (int)Grade.C);
            Assert.Equal(3, (int)Grade.D);
            Assert.Equal(4, (int)Grade.F);
        }
    }
}

