public static SchoolContext CreateWithData(string dbName = null)
{
    var context = Create(dbName ?? Guid.NewGuid().ToString());
    SeedData(context);
    return context;
}

public static void SeedData(SchoolContext context)
{
    var instructor1 = new Instructor
    {
        LastName = "Smith",
        FirstMidName = "John",
        HireDate = new DateTime(2015, 3, 15),
        CourseAssignments = new List<CourseAssignment>()
    };
    var instructor2 = new Instructor
    {
        LastName = "Johnson",
        FirstMidName = "Jane",
        HireDate = new DateTime(2018, 8, 20),
        CourseAssignments = new List<CourseAssignment>()
    };
    context.Instructors.AddRange(instructor1, instructor2);
    context.SaveChanges();

    var dept1 = new Department
    {
        Name = "Engineering",
        Budget = 100000m,
        StartDate = new DateTime(2020, 1, 1)
    };
    var dept2 = new Department
    {
        Name = "Mathematics",
        Budget = 80000m,
        StartDate = new DateTime(2019, 6, 1)
    };
    context.Departments.AddRange(dept1, dept2);
    context.SaveChanges();

    var course1 = new Course
    {
        CourseID = 1001,
        Title = "Chemistry",
        Credits = 3,
        DepartmentID = dept1.DepartmentID,
        Enrollments = new List<Enrollment>(),
        CourseAssignments = new List<CourseAssignment>()
    };
    var course2 = new Course
    {
        CourseID = 1002,
        Title = "Physics",
        Credits = 4,
        DepartmentID = dept2.DepartmentID,
        Enrollments = new List<Enrollment>(),
        CourseAssignments = new List<CourseAssignment>()
    };
    context.Courses.AddRange(course1, course2);
    context.SaveChanges();

    var student1 = new Student
    {
        LastName = "Doe",
        FirstMidName = "Alice",
        EnrollmentDate = new DateTime(2021, 9, 1),
        Enrollments = new List<Enrollment>()
    };
    var student2 = new Student
    {
        LastName = "Brown",
        FirstMidName = "Bob",
        EnrollmentDate = new DateTime(2022, 1, 15),
        Enrollments = new List<Enrollment>()
    };
    var student3 = new Student
    {
        LastName = "Adams",
        FirstMidName = "Charlie",
        EnrollmentDate = new DateTime(2020, 9, 1),
        Enrollments = new List<Enrollment>()
    };
    context.Students.AddRange(student1, student2, student3);
    context.SaveChanges();

    context.Enrollments.AddRange(
        new Enrollment { CourseID = 1001, StudentID = student1.ID, Grade = Grade.A },
        new Enrollment { CourseID = 1002, StudentID = student1.ID, Grade = Grade.B },
        new Enrollment { CourseID = 1001, StudentID = student2.ID, Grade = Grade.C }
    );
    context.SaveChanges();

    context.CourseAssignments.Add(new CourseAssignment { CourseID = 1001, InstructorID = instructor1.ID });
    context.SaveChanges();
}

